package main

import (
	"fmt"
	"math/rand"
	"time"
)

func GenerateSessionToken() string {
	const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	token := make([]byte, 32)
	for i := range token {
		token[i] = chars[rand.Intn(len(chars))]
	}
	return string(token)
}

func main() {
	rand.Seed(time.Now().UnixNano())
	fmt.Println(GenerateSessionToken())
}